const payload = $json.body || $json || {};
const conversation = payload.conversation || {};
const messages = Array.isArray(conversation.messages) ? conversation.messages : [];
const incomingMessage = messages.find((m) => String(m.message_type || '').toLowerCase() === 'incoming') || messages[messages.length - 1] || {};
const sources = [
  payload.attachments,
  incomingMessage.attachments,
  payload.message && payload.message.attachments,
  payload.content_attributes && payload.content_attributes.attachments
].filter(Array.isArray);
const attachments = sources.flat();
const first = attachments[0] || {};

const pickString = (...values) => {
  const val = values.find((v) => typeof v === 'string' && v.trim().length > 0);
  return val ? val.trim() : '';
};

const mediaUrl = pickString(
  first.data_url,
  first.url,
  first.file_url,
  first.external_url,
  first.remote_url,
  first.thumb_url
) || null;

let rawMime = pickString(first.file_type, first.content_type, first.type).toLowerCase();
if (!rawMime && mediaUrl && mediaUrl.startsWith('data:')) {
  rawMime = mediaUrl.slice(5).split(';')[0].toLowerCase();
}

const contentType = pickString(payload.content_type, incomingMessage.content_type).toLowerCase();
const urlLooksImage = !!(mediaUrl && /\.(png|jpe?g|gif|webp|bmp|svg)(\?|$)/i.test(mediaUrl));
const urlLooksAudio = !!(mediaUrl && /\.(mp3|m4a|wav|ogg|aac|opus)(\?|$)/i.test(mediaUrl));
const urlLooksVideo = !!(mediaUrl && /\.(mp4|mov|mkv|webm|avi)(\?|$)/i.test(mediaUrl));

const isImage = rawMime === 'image' || rawMime.startsWith('image/') || contentType === 'image' || contentType.startsWith('image/') || urlLooksImage;
const isAudio = rawMime === 'audio' || rawMime.startsWith('audio/') || contentType === 'audio' || contentType.startsWith('audio/') || urlLooksAudio;
const isVideo = rawMime === 'video' || rawMime.startsWith('video/') || contentType === 'video' || contentType.startsWith('video/') || urlLooksVideo;

let modality = 'text';
if (attachments.length > 0 || mediaUrl) {
  if (isImage) modality = 'image';
  else if (isAudio) modality = 'audio';
  else if (isVideo) modality = 'video';
  else modality = 'file';
} else if (contentType && contentType !== 'text') {
  modality = contentType;
}

return [{
  json: {
    event: payload.event || null,
    message_type: payload.message_type || incomingMessage.message_type || null,
    content: pickString(payload.content, incomingMessage.content),
    conversation_id: payload.conversation_id || conversation.id || incomingMessage.conversation_id || null,
    phone_number: pickString(
      payload?.sender?.phone_number,
      incomingMessage?.sender?.phone_number,
      conversation?.meta?.sender?.phone_number,
      payload?.contact?.phone_number
    ) || null,
    modality,
    media_url: mediaUrl,
    media_mime: rawMime
  }
}];
